module jkff_async_reset(
    input clk,
    input reset,
    input j,
    input k,
    output reg q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
    if (reset)
        q <= 0;
    else if (j & ~k)
        q <= 1;
    else if (~j & k)
        q <= 0;
    else if (j & k)
        q <= ~q;

endmodule
